import{_ as s,o as e,c as n,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"指令教程","description":"","frontmatter":{},"headers":[],"relativePath":"guide/jiaocheng.md","filePath":"guide/jiaocheng.md","lastUpdated":null}'),d={name:"guide/jiaocheng.md"};function p(l,a,i,r,c,o){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="指令教程" tabindex="-1">指令教程 <a class="header-anchor" href="#指令教程" aria-label="Permalink to &quot;指令教程&quot;">​</a></h1><p>从零开始，手把手教你使用修仙服务器的全部指令。</p><hr><h2 id="指令速查表" tabindex="-1">指令速查表 <a class="header-anchor" href="#指令速查表" aria-label="Permalink to &quot;指令速查表&quot;">​</a></h2><h3 id="所有玩家指令" tabindex="-1">所有玩家指令 <a class="header-anchor" href="#所有玩家指令" aria-label="Permalink to &quot;所有玩家指令&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主命令</th><th>缩写/别名</th><th>说明</th></tr></thead><tbody><tr><td><code>/修仙</code></td><td><code>/xx</code></td><td>打开修仙主面板（境界/灵气/灵根/丹药/功法/属性）</td></tr><tr><td><code>/突破 [是/否]</code></td><td><code>/tp</code></td><td>尝试突破境界；加 <code>是</code> 自动使用突破丹</td></tr><tr><td><code>/修炼</code></td><td><code>/xl</code></td><td>开始/停止修炼（定身挂机）</td></tr><tr><td><code>/功法</code></td><td><code>/gf</code></td><td>查看已学习的功法列表</td></tr><tr><td><code>/功法 可学</code></td><td>—</td><td>查看当前可学习的功法</td></tr><tr><td><code>/功法 学习 &lt;ID&gt;</code></td><td>—</td><td>学习指定功法</td></tr><tr><td><code>/功法 释放 &lt;ID&gt;</code></td><td>—</td><td>释放指定功法技能</td></tr><tr><td><code>/炼丹</code></td><td><code>/ld</code></td><td>查看丹药库存</td></tr><tr><td><code>/炼丹 突破</code></td><td>—</td><td>炼制突破丹</td></tr><tr><td><code>/炼丹 修炼</code></td><td>—</td><td>炼制修炼丹</td></tr><tr><td><code>/炼丹 疗伤</code></td><td>—</td><td>炼制疗伤丹</td></tr><tr><td><code>/炼丹 使用 疗伤</code></td><td>—</td><td>使用疗伤丹恢复生命</td></tr><tr><td><code>/修仙排行</code></td><td><code>/xxph</code></td><td>查看在线修仙者排行榜 Top10</td></tr></tbody></table><blockquote><p>💡 <strong>别名是缩写</strong>，例如 <code>/xx</code> 等同于 <code>/修仙</code>，<code>/tp</code> 等同于 <code>/突破</code>——打缩写更快！</p></blockquote><hr><h2 id="第一章-初入修仙-第一天" tabindex="-1">第一章：初入修仙（第一天） <a class="header-anchor" href="#第一章-初入修仙-第一天" aria-label="Permalink to &quot;第一章：初入修仙（第一天）&quot;">​</a></h2><h3 id="_1-1-觉醒灵根" tabindex="-1">1.1 觉醒灵根 <a class="header-anchor" href="#_1-1-觉醒灵根" aria-label="Permalink to &quot;1.1 觉醒灵根&quot;">​</a></h3><p>进入服务器后，系统会自动检测你的灵根资质。输入以下命令查看：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你会看到类似这样的面板：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>══════════ 修仙面板 ══════════</span></span>
<span class="line"><span>境界：凡人</span></span>
<span class="line"><span>灵根：火灵根</span></span>
<span class="line"><span>灵气：100 / 100</span></span>
<span class="line"><span>修为：0 / 150</span></span>
<span class="line"><span>功法：无</span></span>
<span class="line"><span>══════════════════════════════</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_1-2-获取灵气" tabindex="-1">1.2 获取灵气 <a class="header-anchor" href="#_1-2-获取灵气" aria-label="Permalink to &quot;1.2 获取灵气&quot;">​</a></h3><p>击杀怪物是获取灵气的主要方式。每造成 100 伤害可获得约 5 灵气。去野外打几个史莱姆或僵尸攒灵气。</p><h3 id="_1-3-首次突破" tabindex="-1">1.3 首次突破 <a class="header-anchor" href="#_1-3-首次突破" aria-label="Permalink to &quot;1.3 首次突破&quot;">​</a></h3><p>灵气攒到一定程度后，尝试突破到练气期：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/tp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>💡 突破消耗当前灵气的 70%，成功率 37.5%（练气1阶基础值）。失败了别灰心，继续打怪攒灵气重试！</p></blockquote><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 如果用 /xx 查看显示灵气够了但一直失败，</span></span>
<span class="line"><span># 连续失败3次后会触发保护，提高成功率。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="第二章-修炼进阶-第二天" tabindex="-1">第二章：修炼进阶（第二天） <a class="header-anchor" href="#第二章-修炼进阶-第二天" aria-label="Permalink to &quot;第二章：修炼进阶（第二天）&quot;">​</a></h2><h3 id="_2-1-开始修炼" tabindex="-1">2.1 开始修炼 <a class="header-anchor" href="#_2-1-开始修炼" aria-label="Permalink to &quot;2.1 开始修炼&quot;">​</a></h3><p>有了练气期基础后，可以开始挂机修炼：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>系统会提示「开始修炼」，你的角色会进入定身状态。每 10 秒聊天栏会显示进度。</p><p>修炼期间每秒消耗 5 灵气，12% 转化为修为。想要停止修炼再次输入 <code>/xl</code>。</p><h3 id="_2-2-查看功法" tabindex="-1">2.2 查看功法 <a class="header-anchor" href="#_2-2-查看功法" aria-label="Permalink to &quot;2.2 查看功法&quot;">​</a></h3><p>输入以下命令查看已解锁的功法：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-3-学习功法" tabindex="-1">2.3 学习功法 <a class="header-anchor" href="#_2-3-学习功法" aria-label="Permalink to &quot;2.3 学习功法&quot;">​</a></h3><p>达到对应境界+小阶后，可以学习功法：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gf 可学         # 查看可学功法列表</span></span>
<span class="line"><span>/gf 学习 1       # 学习ID为1的功法（灵气弹）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-4-释放功法" tabindex="-1">2.4 释放功法 <a class="header-anchor" href="#_2-4-释放功法" aria-label="Permalink to &quot;2.4 释放功法&quot;">​</a></h3><p>学习后使用功法技能：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gf 释放 1       # 释放灵气弹</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>⚠️ 功法有全局冷却5秒！释放后需要等5秒才能用下一个。</p></blockquote><hr><h2 id="第三章-炼丹制药" tabindex="-1">第三章：炼丹制药 <a class="header-anchor" href="#第三章-炼丹制药" aria-label="Permalink to &quot;第三章：炼丹制药&quot;">​</a></h2><h3 id="_3-1-查看丹药库存" tabindex="-1">3.1 查看丹药库存 <a class="header-anchor" href="#_3-1-查看丹药库存" aria-label="Permalink to &quot;3.1 查看丹药库存&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ld</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-2-炼制突破丹" tabindex="-1">3.2 炼制突破丹 <a class="header-anchor" href="#_3-2-炼制突破丹" aria-label="Permalink to &quot;3.2 炼制突破丹&quot;">​</a></h3><p>突破丹能大幅提高突破成功率：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ld 突破        # 自动选择能炼制的最高品质</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>炼制需要消耗灵气和修为（中等品质以上），且高级/极品有失败受伤风险。建议在修仙等级较高时挑战极品丹药。</p><h3 id="_3-3-炼制修炼丹" tabindex="-1">3.3 炼制修炼丹 <a class="header-anchor" href="#_3-3-炼制修炼丹" aria-label="Permalink to &quot;3.3 炼制修炼丹&quot;">​</a></h3><p>修炼丹可以加速修炼效率（持续90秒）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ld 修炼</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>🌊 修炼丹 + 灵气潮汐事件 = 修炼效率 ×2.25！</p></blockquote><h3 id="_3-4-疗伤" tabindex="-1">3.4 疗伤 <a class="header-anchor" href="#_3-4-疗伤" aria-label="Permalink to &quot;3.4 疗伤&quot;">​</a></h3><p>战斗中受伤了？用疗伤丹回血：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ld 疗伤        # 炼制疗伤丹</span></span>
<span class="line"><span>/ld 使用 疗伤   # 使用疗伤丹</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="第四章-突破攻略" tabindex="-1">第四章：突破攻略 <a class="header-anchor" href="#第四章-突破攻略" aria-label="Permalink to &quot;第四章：突破攻略&quot;">​</a></h2><h3 id="_4-1-带丹突破" tabindex="-1">4.1 带丹突破 <a class="header-anchor" href="#_4-1-带丹突破" aria-label="Permalink to &quot;4.1 带丹突破&quot;">​</a></h3><p>突破时可以自动使用突破丹（前提是你有库存）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/tp 是          # 使用突破丹辅助突破</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-2-大境界突破流程" tabindex="-1">4.2 大境界突破流程 <a class="header-anchor" href="#_4-2-大境界突破流程" aria-label="Permalink to &quot;4.2 大境界突破流程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. /xx          # 确认当前是第9小阶</span></span>
<span class="line"><span>2. /gf 释放 X   # 击杀所需Boss（详见境界页面）</span></span>
<span class="line"><span>3. /ld 突破     # 炼制突破丹</span></span>
<span class="line"><span>4. /tp 是       # 带丹突破</span></span>
<span class="line"><span>5. 金丹及以上需渡劫——扛住天雷！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="_4-3-渡劫要点" tabindex="-1">4.3 渡劫要点 <a class="header-anchor" href="#_4-3-渡劫要点" aria-label="Permalink to &quot;4.3 渡劫要点&quot;">​</a></h3><ul><li>金丹起每次大境界突破都要渡劫</li><li>天雷数量和伤害随境界递增（飞升18道每道400伤）</li><li>天道境界越高减免越多（最高-40%）</li><li>务必提前备好渡劫丹和回复药水</li></ul><hr><h2 id="第五章-查看排行榜" tabindex="-1">第五章：查看排行榜 <a class="header-anchor" href="#第五章-查看排行榜" aria-label="Permalink to &quot;第五章：查看排行榜&quot;">​</a></h2><p>想看看谁是这个服务器最强修士？</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xxph</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>显示在线修仙者排行榜 Top10，按境界和灵气排序。</p><hr><h2 id="第六章-完整指令流程演示" tabindex="-1">第六章：完整指令流程演示 <a class="header-anchor" href="#第六章-完整指令流程演示" aria-label="Permalink to &quot;第六章：完整指令流程演示&quot;">​</a></h2><p>以下是一个从零到飞升的指令使用流程：</p><h3 id="练气期-1-9阶" tabindex="-1">练气期（1-9阶） <a class="header-anchor" href="#练气期-1-9阶" aria-label="Permalink to &quot;练气期（1-9阶）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xx              # 查看初始面板</span></span>
<span class="line"><span>（打怪攒灵气...）</span></span>
<span class="line"><span>/tp              # 突破练气1阶（自动觉醒灵根）</span></span>
<span class="line"><span>/xl              # 开始修炼攒修为</span></span>
<span class="line"><span>/tp              # 突破练气2阶</span></span>
<span class="line"><span>...重复...</span></span>
<span class="line"><span>/tp              # 突破练气9阶</span></span>
<span class="line"><span>/gf 可学         # 查看功法</span></span>
<span class="line"><span>/gf 学习 1       # 学灵气弹</span></span>
<span class="line"><span>/gf 学习 2       # 学灵刃斩</span></span>
<span class="line"><span>/ld 突破         # 备好突破丹</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="筑基期-击杀克苏鲁之眼后" tabindex="-1">筑基期（击杀克苏鲁之眼后） <a class="header-anchor" href="#筑基期-击杀克苏鲁之眼后" aria-label="Permalink to &quot;筑基期（击杀克苏鲁之眼后）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gf 释放 1       # 实战用功法打Boss</span></span>
<span class="line"><span>（击杀克苏鲁之眼...）</span></span>
<span class="line"><span>/tp 是           # 带丹突破到筑基</span></span>
<span class="line"><span>/xl              # 继续修炼</span></span>
<span class="line"><span>/gf 可学         # 筑基期新功法</span></span>
<span class="line"><span>/gf 学习 6       # 学御剑术</span></span>
<span class="line"><span>/gf 学习 7       # 学缩地成寸</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="金丹期-击杀骷髅王后" tabindex="-1">金丹期（击杀骷髅王后） <a class="header-anchor" href="#金丹期-击杀骷髅王后" aria-label="Permalink to &quot;金丹期（击杀骷髅王后）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>（击杀骷髅王...）</span></span>
<span class="line"><span>/tp 是           # 带丹突破→渡劫</span></span>
<span class="line"><span>（扛过3道天雷...）</span></span>
<span class="line"><span>/ld 修炼         # 炼修炼丹加速</span></span>
<span class="line"><span>/xl              # 修炼丹+修炼效率激增</span></span>
<span class="line"><span>/gf 学习 11      # 学丹火焚天</span></span>
<span class="line"><span>/gf 学习 13      # 学金钟罩</span></span>
<span class="line"><span>/ld 使用 疗伤    # 渡劫后回血</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="元婴-飞升" tabindex="-1">元婴~飞升 <a class="header-anchor" href="#元婴-飞升" aria-label="Permalink to &quot;元婴~飞升&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>（击杀双子魔眼→世纪之花→拜月教徒→月总）</span></span>
<span class="line"><span>/tp 是           # 每次大境界突破都带丹</span></span>
<span class="line"><span>/ld 突破         # 优先炼极品突破丹</span></span>
<span class="line"><span>/ld 疗伤         # 备好疗伤丹防渡劫失败</span></span>
<span class="line"><span>/gf 可学         # 每阶段学新功法</span></span>
<span class="line"><span>/gf 释放 22      # 万剑归宗！</span></span>
<span class="line"><span>/gf 释放 28      # 飞升羽化——终极功法！</span></span>
<span class="line"><span>/xxph            # 查看你在排行榜第几名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><hr><h2 id="指令缩写对照表" tabindex="-1">指令缩写对照表 <a class="header-anchor" href="#指令缩写对照表" aria-label="Permalink to &quot;指令缩写对照表&quot;">​</a></h2><p>老玩家都用缩写，打字更快：</p><table tabindex="0"><thead><tr><th>完整指令</th><th>缩写</th><th>含义</th></tr></thead><tbody><tr><td><code>/修仙</code></td><td><code>/xx</code></td><td>修→x, 仙→x → xx</td></tr><tr><td><code>/突破</code></td><td><code>/tp</code></td><td>突→t, 破→p → tp</td></tr><tr><td><code>/修炼</code></td><td><code>/xl</code></td><td>修→x, 炼→l → xl</td></tr><tr><td><code>/功法</code></td><td><code>/gf</code></td><td>功→g, 法→f → gf</td></tr><tr><td><code>/炼丹</code></td><td><code>/ld</code></td><td>炼→l, 丹→d → ld</td></tr><tr><td><code>/修仙排行</code></td><td><code>/xxph</code></td><td>修仙→xx, 排行→ph</td></tr></tbody></table><blockquote><p>🎯 实战中 <code>/tp 是</code> 是最常用的指令之一——带丹突破，三个字搞定！</p></blockquote><hr><h2 id="管理指令-服主用" tabindex="-1">管理指令（服主用） <a class="header-anchor" href="#管理指令-服主用" aria-label="Permalink to &quot;管理指令（服主用）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/修仙管理 帮助</code></td><td>查看管理命令帮助</td></tr><tr><td><code>/修仙管理 设置境界 &lt;玩家&gt; &lt;境界&gt; [小阶]</code></td><td>设置玩家境界</td></tr><tr><td><code>/修仙管理 设置灵气 &lt;玩家&gt; &lt;数值&gt;</code></td><td>设置玩家灵气</td></tr><tr><td><code>/修仙管理 设置灵根 &lt;玩家&gt; &lt;灵根&gt;</code></td><td>设置玩家灵根</td></tr><tr><td><code>/修仙管理 查看 &lt;玩家&gt;</code></td><td>查看玩家数据</td></tr><tr><td><code>/修仙管理 重置 &lt;玩家&gt;</code></td><td>重置玩家修仙数据</td></tr><tr><td><code>/修仙管理 保存</code></td><td>立即保存所有数据</td></tr><tr><td><code>/reload</code></td><td>热加载配置文件</td></tr></tbody></table><p>灵根可选：<code>金</code> <code>木</code> <code>水</code> <code>火</code> <code>土</code> <code>天</code> 境界可选：<code>凡人</code> <code>练气</code> <code>筑基</code> <code>金丹</code> <code>元婴</code> <code>化神</code> <code>渡劫</code> <code>大乘</code> <code>飞升</code></p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-tp-和-terraria-的传送指令冲突吗" tabindex="-1">Q: <code>/tp</code> 和 Terraria 的传送指令冲突吗？ <a class="header-anchor" href="#q-tp-和-terraria-的传送指令冲突吗" aria-label="Permalink to &quot;Q: \`/tp\` 和 Terraria 的传送指令冲突吗？&quot;">​</a></h3><p>不冲突。修仙插件的 <code>/tp</code> 是 <code>/突破</code> 的缩写，和原版 <code>/tp</code> (teleport) 是不同的命令前缀。</p><h3 id="q-修炼时能移动吗" tabindex="-1">Q: 修炼时能移动吗？ <a class="header-anchor" href="#q-修炼时能移动吗" aria-label="Permalink to &quot;Q: 修炼时能移动吗？&quot;">​</a></h3><p>不能。修炼期间会定身，再次输入 <code>/xl</code> 停止修炼即可恢复移动。</p><h3 id="q-突破一直失败怎么办" tabindex="-1">Q: 突破一直失败怎么办？ <a class="header-anchor" href="#q-突破一直失败怎么办" aria-label="Permalink to &quot;Q: 突破一直失败怎么办？&quot;">​</a></h3><p>连续失败3次会触发保护机制，成功率会提高。同时建议：</p><ol><li>使用突破丹 <code>/tp 是</code></li><li>等待天道试炼事件（+15%成功率）</li><li>提升天道境界获得额外加成</li></ol><h3 id="q-怎么看自己的灵根" tabindex="-1">Q: 怎么看自己的灵根？ <a class="header-anchor" href="#q-怎么看自己的灵根" aria-label="Permalink to &quot;Q: 怎么看自己的灵根？&quot;">​</a></h3><p>输入 <code>/xx</code> 打开修仙面板，会显示灵根类型。</p><h3 id="q-功法id怎么看" tabindex="-1">Q: 功法ID怎么看？ <a class="header-anchor" href="#q-功法id怎么看" aria-label="Permalink to &quot;Q: 功法ID怎么看？&quot;">​</a></h3><p>输入 <code>/gf 可学</code> 查看可学功法列表，每门功法都有对应ID。</p>`,100)])])}const u=s(d,[["render",p]]);export{b as __pageData,u as default};
